import urllib.request
import PyPDF2
import io

def get_pdf_text(url):
    req = urllib.request.Request(url, headers={'User-Agent': 'Mozilla/5.0'})
    with urllib.request.urlopen(req) as response:
        pdf_file = io.BytesIO(response.read())
        reader = PyPDF2.PdfReader(pdf_file)
        text = ""
        for page in reader.pages:
            text += page.extract_text() + "\n"
        return text

try:
    gs3 = get_pdf_text("https://www.dominionenergy.com/-/media/content/rates-and-tariffs/pdfs/virginia/large-business/schedule-gs3.pdf")
    gs4 = get_pdf_text("https://www.dominionenergy.com/-/media/content/rates-and-tariffs/pdfs/virginia/large-business/schedule-gs4.pdf")
    print("GS-3 Demand Charges:")
    for line in gs3.split('\n'):
        if 'Demand' in line and '$' in line:
            print(line.strip())
    print("\nGS-4 Demand Charges:")
    for line in gs4.split('\n'):
        if 'Demand' in line and '$' in line:
            print(line.strip())
except Exception as e:
    print(e)

